const crypto = require('crypto');

const keyId     = 'YOUR_SOLIS_KEY_ID';
const keySecret = 'YOUR_SOLIS_KEY_SECRET';
const apiPath   = '/v1/api/inverterList';

const bodyObj = { pageNo: 1, pageSize: 10 };
const body    = JSON.stringify(bodyObj);

const D = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const M = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const t = new Date();
const dateStr = `${D[t.getUTCDay()]}, ${String(t.getUTCDate()).padStart(2,'0')} ${M[t.getUTCMonth()]} ${t.getUTCFullYear()} ${String(t.getUTCHours()).padStart(2,'0')}:${String(t.getUTCMinutes()).padStart(2,'0')}:${String(t.getUTCSeconds()).padStart(2,'0')} GMT`;

const md5     = crypto.createHash('md5').update(body, 'utf8').digest('base64');
const signStr = 'POST\n' + md5 + '\napplication/json\n' + dateStr + '\n' + apiPath;
const sign    = crypto.createHmac('sha1', keySecret).update(signStr).digest('base64');

return [{
  json: {
    authHeader:  'API ' + keyId + ':' + sign,
    contentMD5:  md5,
    dateHeader:  dateStr,
    requestBody: bodyObj
  }
}];

const INTERVAL     = 10;
const CRITICAL_SOC = 30;

const records = $input.first().json.data.page.records;
const state = $getWorkflowStaticData('global');
if (!state.bands) state.bands = {};

const alerts = [];

const now     = new Date();
const utc8    = new Date(now.getTime() + 8 * 60 * 60 * 1000);
const hour    = utc8.getUTCHours();
const timeStr = utc8.toISOString().replace('T', ' ').slice(0, 19) + ' (UTC+8)';

const isQuietHours = hour >= 0 && hour < 6;

for (const inv of records) {
  const soc           = inv.batteryCapacitySoc;
  const isDischarging = inv.batteryPower < 0;
  const currentBand   = Math.floor(soc / INTERVAL) * INTERVAL;
  const isCritical    = soc <= CRITICAL_SOC;

  if (state.bands[inv.id] === undefined) {
    state.bands[inv.id] = currentBand;
    continue;
  }

  const lastBand = state.bands[inv.id];

  if (isDischarging && currentBand < lastBand) {
    state.bands[inv.id] = currentBand;

    const loopStart = Math.min(lastBand, 90);

    for (let threshold = loopStart; threshold > currentBand; threshold -= INTERVAL) {

      let route;
      if (!isQuietHours) {
        route = 'send';
      } else if (isCritical) {
        route = 'critical';
      } else {
        route = 'silent';
      }

      alerts.push({
        notify:        true,
        route:         route,
        station:       inv.stationName,
        soc:           soc,
        crossed_below: threshold,
        power_kw:      Math.abs(inv.batteryPower),
        is_critical:   isCritical,
        is_quiet:      isQuietHours,
        time:          timeStr,
        message:       `${isCritical ? '🚨' : '🔋'} ${inv.stationName}\n\nBattery dropped below <b>${threshold}%</b>\nNow at <b>${soc}%</b> — discharging at <b>${Math.abs(inv.batteryPower)} kW</b>\n\n🕐 ${timeStr}`,
      });
    }

  } else if (!isDischarging) {
    state.bands[inv.id] = currentBand;
  }
}

if (alerts.length === 0) {
  return [{ json: { notify: false, route: 'no_alert', is_quiet: isQuietHours } }];
}

return alerts.map(a => ({ json: a }));
